def gen(rng, size):
    def is_prime(v):
        if v < 2:
            return False
        if v % 2 == 0:
            return v == 2
        f = 3
        while f * f <= v:
            if v % f == 0:
                return False
            f += 2
        return True
    n = max(1, min(size, 100))
    hi = 1000
    nums = []
    while len(nums) < n:
        v = rng.randint(2, hi)
        if is_prime(v):
            nums.append(v)
    return [nums]

