class Solution:
    def minBitwiseArray(self, nums):
        ans = []
        for n in nums:
            if n % 2 == 0:
                ans.append(-1)
                continue
            best_k = 0
            k = 0
            while True:
                mask = (1 << (k + 1)) - 1
                if (n & mask) == mask:
                    best_k = k
                    k += 1
                else:
                    break
            ans.append(n - (1 << best_k))
        return ans

