class Solution:
    def minBitwiseArray(self, nums):
        ans = []
        for n in nums:
            if n % 2 == 0:
                ans.append(-1)
                continue
            low = (n + 1) & (-(n + 1))
            ans.append(n - low // 2)
        return ans

