var minBitwiseArray = function(nums) {
    const ans = [];
    for (const n of nums) {
        if (n % 2 === 0) { ans.push(-1); continue; }
        const low = (n + 1) & (-(n + 1));
        ans.push(n - Math.floor(low / 2));
    }
    return ans;
